 1→import type { RecordId } from "surrealdb";
 2→import type { EntityPriority } from "../../shared/contracts";
 3→
 4→export type {
 5→  LearningType,
 6→  LearningStatus,
 7→  LearningSource,
 8→  LearningSummary,
 9→} from "../../shared/contracts";
10→
11→export type LearningRecord = RecordId<"learning", string>;
12→export type EvidenceTargetRecord = RecordId<"message" | "trace" | "observation" | "agent_session", string>;
13→
14→export type CreateLearningInput = {
15→  text: string;
16→  learningType: "constraint" | "instruction" | "precedent";
17→  priority?: EntityPriority;
18→  targetAgents?: string[];
19→  source: "human" | "agent";
20→  suggestedBy?: string;
21→  patternConfidence?: number;
22→  createdBy?: string;
23→  evidenceIds?: Array<{ table: "message" | "trace" | "observation" | "agent_session"; id: string }>;
24→  /** Override default status (e.g. force pending_approval when collision blocks activation) */
25→  forceStatus?: "active" | "pending_approval";
26→};
27→

  1→import { randomUUID } from "node:crypto";
  2→import { RecordId, Surreal } from "surrealdb";
  3→import type { EntityPriority, LearningStatus, LearningType, LearningSource, LearningSummary } from "../../shared/contracts";
  4→import type { CreateLearningInput, EvidenceTargetRecord, LearningRecord } from "./types";
  5→
  6→// ---------------------------------------------------------------------------
  7→// Create
  8→// ---------------------------------------------------------------------------
  9→
 10→export async function createLearning(input: {
 11→  surreal: Surreal;
 12→  workspaceRecord: RecordId<"workspace", string>;
 13→  learning: CreateLearningInput;
 14→  now: Date;
 15→  embedding?: number[];
 16→}): Promise<LearningRecord> {
 17→  const learningRecord = new RecordId("learning", randomUUID());
 18→
 19→  const defaultStatus: LearningStatus = input.learning.source === "human" ? "active" : "pending_approval";
 20→  const status: LearningStatus = input.learning.forceStatus ?? defaultStatus;
 21→  const isActive = status === "active";
 22→
 23→  await input.surreal.create(learningRecord).content({
 24→    text: input.learning.text,
 25→    learning_type: input.learning.learningType,
 26→    status,
 27→    source: input.learning.source,
 28→    priority: input.learning.priority ?? "medium",
 29→    target_agents: input.learning.targetAgents ?? [],
 30→    workspace: input.workspaceRecord,
 31→    ...(input.learning.suggestedBy ? { suggested_by: input.learning.suggestedBy } : {}),
 32→    ...(input.learning.patternConfidence !== undefined ? { pattern_confidence: input.learning.patternConfidence } : {}),
 33→    ...(input.learning.createdBy ? { created_by: new RecordId("identity", input.learning.createdBy) } : {}),
 34→    ...(input.embedding ? { embedding: input.embedding } : {}),
 35→    ...(isActive ? { activated_at: input.now } : {}),
 36→    created_at: input.now,
 37→    updated_at: input.now,
 38→  });
 39→
 40→  // Create evidence edges
 41→  if (input.learning.evidenceIds && input.learning.evidenceIds.length > 0) {
 42→    for (const evidence of input.learning.evidenceIds) {
 43→      const evidenceRecord = new RecordId(evidence.table, evidence.id) as EvidenceTargetRecord;
 44→      await input.surreal
 45→        .relate(learningRecord, new RecordId("learning_evidence", randomUUID()), evidenceRecord, {
 46→          added_at: input.now,
 47→        })
 48→        .output("after");
 49→    }
 50→  }
 51→
 52→  return learningRecord;
 53→}
 54→
 55→// ---------------------------------------------------------------------------
 56→// Status transitions
 57→// ---------------------------------------------------------------------------
 58→
 59→export async function updateLearningStatus(input: {
 60→  surreal: Surreal;
 61→  workspaceRecord: RecordId<"workspace", string>;
 62→  learningRecord: LearningRecord;
 63→  newStatus: LearningStatus;
 64→  now: Date;
 65→  actorRecord?: RecordId<"identity", string>;
 66→  reason?: string;
 67→}): Promise<void> {
 68→  const row = await input.surreal.select<{ workspace: RecordId<"workspace", string>; status: LearningStatus }>(input.learningRecord);
 69→  if (!row) {
 70→    throw new Error(`learning not found: ${input.learningRecord.id as string}`);
 71→  }
 72→
 73→  if ((row.workspace.id as string) !== (input.workspaceRecord.id as string)) {
 74→    throw new Error("learning is outside the current workspace scope");
 75→  }
 76→
 77→  const auditFields = buildAuditFields(input.newStatus, input.now, input.actorRecord, input.reason);
 78→
 79→  await input.surreal.update(input.learningRecord).merge({
 80→    status: input.newStatus,
 81→    updated_at: input.now,
 82→    ...auditFields,
 83→  });
 84→}
 85→
 86→function buildAuditFields(
 87→  newStatus: LearningStatus,
 88→  now: Date,
 89→  actorRecord?: RecordId<"identity", string>,
 90→  reason?: string,
 91→): Record<string, unknown> {
 92→  switch (newStatus) {
 93→    case "active":
 94→      return {
 95→        activated_at: now,
 96→        ...(actorRecord ? { approved_by: actorRecord } : {}),
 97→        approved_at: now,
 98→      };
 99→    case "dismissed":
100→      return {
101→        dismissed_at: now,
102→        ...(actorRecord ? { dismissed_by: actorRecord } : {}),
103→        ...(reason ? { dismissed_reason: reason } : {}),
104→      };
105→    case "deactivated":
106→      return {
107→        deactivated_at: now,
108→        ...(actorRecord ? { deactivated_by: actorRecord } : {}),
109→      };
110→    case "superseded":
111→      return {};
112→    case "pending_approval":
113→      return {};
114→  }
115→}
116→
117→// ---------------------------------------------------------------------------
118→// Supersession
119→// ---------------------------------------------------------------------------
120→
121→export async function supersedeLearning(input: {
122→  surreal: Surreal;
123→  workspaceRecord: RecordId<"workspace", string>;
124→  oldLearningRecord: LearningRecord;
125→  newLearningRecord: LearningRecord;
126→  reason?: string;
127→  now: Date;
128→}): Promise<void> {
129→  // Validate workspace scope for old learning
130→  const oldRow = await input.surreal.select<{ workspace: RecordId<"workspace", string> }>(input.oldLearningRecord);
131→  if (!oldRow) {
132→    throw new Error(`learning not found: ${input.oldLearningRecord.id as string}`);
133→  }
134→  if ((oldRow.workspace.id as string) !== (input.workspaceRecord.id as string)) {
135→    throw new Error("learning is outside the current workspace scope");
136→  }
137→
138→  // Deactivate old learning
139→  await input.surreal.update(input.oldLearningRecord).merge({
140→    status: "superseded" satisfies LearningStatus,
141→    updated_at: input.now,
142→  });
143→
144→  // Create supersedes edge: new -> old
145→  await input.surreal
146→    .relate(input.newLearningRecord, new RecordId("supersedes", randomUUID()), input.oldLearningRecord, {
147→      superseded_at: input.now,
148→      ...(input.reason ? { reason: input.reason } : {}),
149→    })
150→    .output("after");
151→}
152→
153→// ---------------------------------------------------------------------------
154→// List queries
155→// ---------------------------------------------------------------------------
156→
157→export async function listWorkspaceActiveLearnings(input: {
158→  surreal: Surreal;
159→  workspaceRecord: RecordId<"workspace", string>;
160→  agentType?: string;
161→}): Promise<LearningSummary[]> {
162→  const query = input.agentType
163→    ? [
164→        "SELECT id, text, learning_type, status, source, priority, target_agents,",
165→        "suggested_by, pattern_confidence, created_at, approved_at, dismissed_at,",
166→        "dismissed_reason, deactivated_at",
167→        "FROM learning",
168→        "WHERE workspace = $workspace",
169→        'AND status = "active"',
170→        "AND (array::len(target_agents) = 0 OR $agentType IN target_agents)",
171→        "ORDER BY created_at DESC;",
172→      ].join(" ")
173→    : [
174→        "SELECT id, text, learning_type, status, source, priority, target_agents,",
175→        "suggested_by, pattern_confidence, created_at, approved_at, dismissed_at,",
176→        "dismissed_reason, deactivated_at",
177→        "FROM learning",
178→        "WHERE workspace = $workspace",
179→        'AND status = "active"',
180→        "ORDER BY created_at DESC;",
181→      ].join(" ");
182→
183→  const [rows] = await input.surreal
184→    .query<[LearningRow[]]>(query, {
185→      workspace: input.workspaceRecord,
186→      ...(input.agentType ? { agentType: input.agentType } : {}),
187→    })
188→    .collect<[LearningRow[]]>();
189→
190→  return rows.map(toLearnings);
191→}
192→
193→export async function listWorkspacePendingLearnings(input: {
194→  surreal: Surreal;
195→  workspaceRecord: RecordId<"workspace", string>;
196→  limit?: number;
197→}): Promise<LearningSummary[]> {
198→  const [rows] = await input.surreal
199→    .query<[LearningRow[]]>(
200→      [
201→        "SELECT id, text, learning_type, status, source, priority, target_agents,",
202→        "suggested_by, pattern_confidence, created_at, approved_at, dismissed_at,",
203→        "dismissed_reason, deactivated_at",
204→        "FROM learning",
205→        "WHERE workspace = $workspace",
206→        'AND status = "pending_approval"',
207→        "ORDER BY created_at DESC",
208→        "LIMIT $limit;",
209→      ].join(" "),
210→      {
211→        workspace: input.workspaceRecord,
212→        limit: input.limit ?? 50,
213→      },
214→    )
215→    .collect<[LearningRow[]]>();
216→
217→  return rows.map(toLearnings);
218→}
219→
220→// ---------------------------------------------------------------------------
221→// Rate-limit counting
222→// ---------------------------------------------------------------------------
223→
224→export async function countRecentSuggestionsByAgent(input: {
225→  surreal: Surreal;
226→  workspaceRecord: RecordId<"workspace", string>;
227→  agentType: string;
228→}): Promise<number> {
229→  const [rows] = await input.surreal
230→    .query<[Array<{ count: number }>]>(
231→      [
232→        "SELECT count() AS count FROM learning",
233→        "WHERE workspace = $workspace",
234→        'AND source = "agent"',
235→        "AND suggested_by = $agentType",
236→        "AND created_at > time::now() - 7d;",
237→      ].join(" "),
238→      {
239→        workspace: input.workspaceRecord,
240→        agentType: input.agentType,
241→      },
242→    )
243→    .collect<[Array<{ count: number }>]>();
244→
245→  return rows[0]?.count ?? 0;
246→}
247→
248→// ---------------------------------------------------------------------------
249→// Internal helpers
250→// ---------------------------------------------------------------------------
251→
252→type LearningRow = {
253→  id: LearningRecord;
254→  text: string;
255→  learning_type: LearningType;
256→  status: LearningStatus;
257→  source: LearningSource;
258→  priority: EntityPriority;
259→  target_agents: string[];
260→  suggested_by?: string;
261→  pattern_confidence?: number;
262→  created_at: string | Date;
263→  approved_at?: string | Date;
264→  dismissed_at?: string | Date;
265→  dismissed_reason?: string;
266→  deactivated_at?: string | Date;
267→};
268→
269→function toLearnings(row: LearningRow): LearningSummary {
270→  return {
271→    id: row.id.id as string,
272→    text: row.text,
273→    learningType: row.learning_type,
274→    status: row.status,
275→    source: row.source,
276→    priority: row.priority,
277→    targetAgents: row.target_agents,
278→    ...(row.suggested_by ? { suggestedBy: row.suggested_by } : {}),
279→    ...(row.pattern_confidence !== undefined ? { patternConfidence: row.pattern_confidence } : {}),
280→    createdAt: toISOString(row.created_at),
281→    ...(row.approved_at ? { approvedAt: toISOString(row.approved_at) } : {}),
282→    ...(row.dismissed_at ? { dismissedAt: toISOString(row.dismissed_at) } : {}),
283→    ...(row.dismissed_reason ? { dismissedReason: row.dismissed_reason } : {}),
284→    ...(row.deactivated_at ? { deactivatedAt: toISOString(row.deactivated_at) } : {}),
285→  };
286→}
287→
288→// ---------------------------------------------------------------------------
289→// Filtered list (for HTTP GET endpoint)
290→// ---------------------------------------------------------------------------
291→
292→export async function listWorkspaceLearnings(input: {
293→  surreal: Surreal;
294→  workspaceRecord: RecordId<"workspace", string>;
295→  status?: LearningStatus;
296→  learningType?: LearningType;
297→  agentType?: string;
298→  limit?: number;
299→}): Promise<LearningSummary[]> {
300→  const clauses = ["WHERE workspace = $workspace"];
301→  const vars: Record<string, unknown> = {
302→    workspace: input.workspaceRecord,
303→    limit: input.limit ?? 100,
304→  };
305→
306→  if (input.status) {
307→    clauses.push("AND status = $status");
308→    vars.status = input.status;
309→  }
310→  if (input.learningType) {
311→    clauses.push("AND learning_type = $learningType");
312→    vars.learningType = input.learningType;
313→  }
314→  if (input.agentType) {
315→    clauses.push("AND (array::len(target_agents) = 0 OR $agentType IN target_agents)");
316→    vars.agentType = input.agentType;
317→  }
318→
319→  const sql = [
320→    "SELECT id, text, learning_type, status, source, priority, target_agents,",
321→    "suggested_by, pattern_confidence, created_at, approved_at, dismissed_at,",
322→    "dismissed_reason, deactivated_at",
323→    "FROM learning",
324→    ...clauses,
325→    "ORDER BY created_at DESC",
326→    "LIMIT $limit;",
327→  ].join(" ");
328→
329→  const [rows] = await input.surreal
330→    .query<[LearningRow[]]>(sql, vars)
331→    .collect<[LearningRow[]]>();
332→
333→  return rows.map(toLearnings);
334→}
