 17→
 18→// ---------------------------------------------------------------------------
 19→// Valid state transitions
 20→// ---------------------------------------------------------------------------
 21→
 22→const VALID_TRANSITIONS: Record<string, Record<string, LearningStatus>> = {
 23→  pending_approval: {
 24→    approve: "active",
 25→    dismiss: "dismissed",
 26→  },
 27→  active: {
 28→    deactivate: "deactivated",
 29→  },
 30→};
 31→
 32→const VALID_ACTIONS = ["approve", "dismiss", "deactivate", "supersede"] as const;
 33→type LearningAction = (typeof VALID_ACTIONS)[number];
